import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { toast } from 'sonner';
import { loginServiceStaff } from '@/db/api';
import { useAuth } from '@/contexts/AuthContext';

const LOGO = "data:image/png;base64,";

const LoginPage: React.FC = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const { login } = useAuth();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!username || !password) {
      toast.error('请输入账号和密码');
      return;
    }
    setLoading(true);
    try {
      const user = await loginServiceStaff(username, password);
      if (user) {
        login(user);
        toast.success('登录成功');
        navigate('/');
      } else {
        toast.error('账号或密码错误');
      }
    } catch (error) {
      console.error('登录失败:', error);
      toast.error('登录失败，请重试');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center" style={{ background: 'linear-gradient(135deg, #0f2a5e 0%, #1e4da8 100%)' }}>
      <div className="w-full max-w-md px-6">
        <div className="flex flex-col items-center mb-8">
          <img src={LOGO} alt="马上国际" className="w-40 h-40 object-contain mb-4 rounded-xl bg-white" />
          <h1 className="text-white text-xl font-bold text-center">广西马上国际货运代理有限公司</h1>
          <p className="text-white/60 text-sm mt-1">客服后台管理系统</p>
        </div>
        <div className="bg-white rounded-2xl p-8 shadow-2xl">
          <h2 className="text-gray-800 text-lg font-semibold mb-6 text-center">账号登录</h2>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="username">账号</Label>
              <Input id="username" type="text" placeholder="请输入账号" value={username} onChange={(e) => setUsername(e.target.value)} disabled={loading} />
            </div>
            <div className="space-y-2">
              <Label htmlFor="password">密码</Label>
              <Input id="password" type="password" placeholder="请输入密码" value={password} onChange={(e) => setPassword(e.target.value)} disabled={loading} />
            </div>
            <Button type="submit" className="w-full mt-2" style={{ background: '#0f2a5e' }} loading={loading} loadingText="登录中...">
              登录
            </Button>
          </form>
        </div>
        <p className="text-white/40 text-xs text-center mt-6">© 2026 广西马上国际货运代理有限公司</p>
      </div>
    </div>
  );
};

export default LoginPage;
